CommandResult tryHeadlessAgentRoute(const char* handlerName, const CommandContext& ctx)
{
    if (!handlerName)
        return CommandResult::error("invalid_handler_name");

    std::string name(handlerName);
    std::string resolverName = name;
    if (resolverName.rfind("handleAi", 0) == 0)
    {
        resolverName.replace(0, std::string("handleAi").size(), "handleAI");
    }
    else if (resolverName.rfind("handleVscext", 0) == 0)
    {
        resolverName.replace(0, std::string("handleVscext").size(), "handleVscExt");
    }
    auto& handlers = RawrXD::Agent::AgentToolHandlers::Instance();
    nlohmann::json args = RawrXD::Core::ParseFallbackArgs(ctx.args);
    std::string tool;
    if (name == "handleAgentExecuteCmd")
    {
        tool = "execute_command";
        if (!args.contains("command") && ctx.args && ctx.args[0] != '\0')
            args["command"] = std::string(ctx.args);
    }
    else
    {
        RawrXD::Core::ResolveFallbackToolRoute(resolverName, ctx.args, args, tool);
    }

    if (tool.empty())
        tool = "load_rules";

    if (tool.empty() || !handlers.HasTool(tool))
    {
        return CommandResult::error("headless_route_no_supported_tool");
    }

    const auto result = handlers.Execute(tool, args);
    if (ctx.outputFn != nullptr)
    {
        const std::string payload = result.toJson().dump() + "\n";
        ctx.output(payload.c_str());
    }
    return result.isSuccess() ? CommandResult::ok("headless_agent_dispatch")
                              : CommandResult::error("headless_agent_dispatch_failed");
}

