CommandResult handleEditClipboardHistory(const CommandContext& ctx)
{
    ctx.output("[Edit] Clipboard history:\n");
    if (OpenClipboard(nullptr)) {
        HANDLE h = GetClipboardData(CF_TEXT);
        if (h) { const char* t = static_cast<const char*>(GlobalLock(h)); if (t) { ctx.output("  Current: "); ctx.output(t); ctx.output("\n"); GlobalUnlock(h); } }
        CloseClipboard();
    } else { ctx.output("  (clipboard empty or locked)\n"); }
    return CommandResult::ok("edit.clipboardHistory");
}
