namespace { struct EditorEngineState { std::string active = "richedit"; std::mutex mtx; }; EditorEngineState g_editorEngineState; }
CommandResult handleEditorEngineCycleCmd(const CommandContext& ctx)
{
    std::lock_guard<std::mutex> lk(g_editorEngineState.mtx);
    if (g_editorEngineState.active == "richedit") g_editorEngineState.active = "monacocore";
    else if (g_editorEngineState.active == "monacocore") g_editorEngineState.active = "webview2";
    else g_editorEngineState.active = "richedit";
    std::string msg = "[Editor] Engine cycled to: " + g_editorEngineState.active + "\n";
    ctx.output(msg.c_str());
    return CommandResult::ok("editor.engine.cycle");
}
