CommandResult handleHelpSearch(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: help search <keyword>\n"); return CommandResult::error("help.search: no keyword"); }
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Help] Searching help for: '%s'\n", ctx.args);
    ctx.output(buf);
    // Simple keyword matching against known command families
    const char* topics[][2] = {
        {"ai", "/ai — AI chat, explain, refactor, generate tests/docs, fix errors"},
        {"edit", "/edit — Find, goto, multicursor, clipboard, snippets"},
        {"file", "/file — Open, save, close, model loading, new window"},
        {"view", "/view — Sidebar, terminal, minimap, zoom, fullscreen"},
        {"theme", "/theme — Switch IDE color themes"},
        {"terminal", "/terminal — Open cmd/powershell, clear, stop"},
        {"debug", "/dbg — Attach, breakpoints, step, memory, registers"},
        {"git", "/git — Repository status panel"},
        {"hotpatch", "/hotpatch — Live binary patching operations"},
        {"lsp", "/lsp — Language server protocol operations"},
        {nullptr, nullptr}
    };
    bool found = false;
    for (int i = 0; topics[i][0]; ++i) {
        if (strstr(topics[i][0], ctx.args) || strstr(topics[i][1], ctx.args)) {
            ctx.output("  "); ctx.output(topics[i][1]); ctx.output("\n"); found = true;
        }
    }
    if (!found) ctx.output("  No matching help topics found\n");
    return CommandResult::ok("help.search");
}
