// HOTPATCH HANDLERS — Live binary patching engine
// ============================================================
namespace {
struct HotpatchState {
    bool enabled = false;
    int patchCount = 0;
    int revertCount = 0;
    struct Server { std::string addr; bool active = true; };
    std::vector<Server> servers;
    std::vector<std::string> eventLog;
    std::mutex mtx;
    void log(const std::string& msg) { if (eventLog.size() > 100) eventLog.erase(eventLog.begin()); eventLog.push_back(msg); }
};
HotpatchState g_hotpatchState;
}

CommandResult handleHotpatchByteApply(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: hotpatch byte_apply <addr> <bytes>\n"); return CommandResult::error("hotpatch.byteApply: no args"); }
    std::lock_guard<std::mutex> lk(g_hotpatchState.mtx);
    g_hotpatchState.patchCount++;
    g_hotpatchState.log(std::string("byte_apply: ") + ctx.args);
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Hotpatch] Byte patch applied (#%d): %s\n", g_hotpatchState.patchCount, ctx.args);
    ctx.output(buf);
    return CommandResult::ok("hotpatch.byteApply");
}
