CommandResult handleHotpatchServerRemove(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: hotpatch server_remove <addr>\n"); return CommandResult::error("hotpatch.serverRemove: no addr"); }
    std::lock_guard<std::mutex> lk(g_hotpatchState.mtx);
    std::string target(ctx.args);
    auto it = std::remove_if(g_hotpatchState.servers.begin(), g_hotpatchState.servers.end(),
        [&](const HotpatchState::Server& s) { return s.addr == target; });
    if (it != g_hotpatchState.servers.end()) {
        g_hotpatchState.servers.erase(it, g_hotpatchState.servers.end());
        g_hotpatchState.log(std::string("server_remove: ") + ctx.args);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[Hotpatch] Server removed: %s\n", ctx.args);
        ctx.output(buf);
    } else { ctx.output("[Hotpatch] Server not found\n"); }
    return CommandResult::ok("hotpatch.serverRemove");
}
