namespace {
struct RevengState {
    std::string loadedBinary;
    bool decompOpen = false;
    std::mutex mtx;
};
RevengState g_revengState;
}

CommandResult handleRevengAnalyze(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: reveng analyze <file>\n"); return CommandResult::error("reveng.analyze: no file"); }
    std::lock_guard<std::mutex> lk(g_revengState.mtx);
    g_revengState.loadedBinary = ctx.args;
    char buf[512]; std::snprintf(buf, sizeof(buf), "[RevEng] Analyzing binary: %s\n", ctx.args);
    ctx.output(buf);
    HANDLE hFile = CreateFileA(ctx.args, GENERIC_READ, FILE_SHARE_READ, nullptr, OPEN_EXISTING, 0, nullptr);
    if (hFile != INVALID_HANDLE_VALUE) {
        LARGE_INTEGER sz; GetFileSizeEx(hFile, &sz);
        unsigned char magic[2] = {0}; DWORD rd; ReadFile(hFile, magic, 2, &rd, nullptr);
        CloseHandle(hFile);
        const char* fmt = (magic[0] == 'M' && magic[1] == 'Z') ? "PE" : "Unknown";
        char buf2[128]; std::snprintf(buf2, sizeof(buf2), "  Format: %s, Size: %lld bytes\n", fmt, sz.QuadPart);
        ctx.output(buf2);
    } else { ctx.output("  File not accessible\n"); }
    return CommandResult::ok("reveng.analyze");
}
