CommandResult handleRevengDumpbin(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: reveng dumpbin <file>\n"); return CommandResult::error("reveng.dumpbin: no file"); }
    char buf[512]; std::snprintf(buf, sizeof(buf), "[RevEng] Dumpbin: %s\n", ctx.args);
    ctx.output(buf);
    // Try running dumpbin
    STARTUPINFOA si{}; si.cb = sizeof(si);
    SECURITY_ATTRIBUTES sa{}; sa.nLength = sizeof(sa); sa.bInheritHandle = TRUE;
    HANDLE hReadPipe, hWritePipe;
    if (CreatePipe(&hReadPipe, &hWritePipe, &sa, 0)) {
        si.hStdOutput = hWritePipe; si.hStdError = hWritePipe; si.dwFlags = STARTF_USESTDHANDLES;
        PROCESS_INFORMATION pi{};
        char cmd[1024]; std::snprintf(cmd, sizeof(cmd), "dumpbin /headers \"%s\"", ctx.args);
        if (CreateProcessA(nullptr, cmd, nullptr, nullptr, TRUE, CREATE_NO_WINDOW, nullptr, nullptr, &si, &pi)) {
            CloseHandle(hWritePipe);
            char rb[4096]; DWORD br; std::string out;
            while (ReadFile(hReadPipe, rb, sizeof(rb)-1, &br, nullptr) && br > 0) { rb[br] = '\0'; out += rb; }
            WaitForSingleObject(pi.hProcess, 5000);
            CloseHandle(pi.hProcess); CloseHandle(pi.hThread);
            if (!out.empty()) ctx.output(out.c_str());
            else ctx.output("  (no dumpbin output)\n");
        } else { CloseHandle(hWritePipe); ctx.output("  dumpbin not found in PATH\n"); }
        CloseHandle(hReadPipe);
    }
    return CommandResult::ok("reveng.dumpbin");
}
