namespace {
struct SwarmState {
    struct Node { std::string addr; bool active = true; bool blacklisted = false; };
    std::vector<Node> nodes;
    bool discoveryEnabled = false;
    bool buildActive = false;
    std::string buildMode;
    int completedTasks = 0;
    std::vector<std::string> events;
    std::mutex mtx;
    void log(const std::string& e) { if (events.size() > 100) events.erase(events.begin()); events.push_back(e); }
};
SwarmState g_swarmState;
}

CommandResult handleSwarmAddNode(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: swarm add_node <addr>\n"); return CommandResult::error("swarm.addNode: no addr"); }
    std::lock_guard<std::mutex> lk(g_swarmState.mtx);
    g_swarmState.nodes.push_back({std::string(ctx.args), true, false});
    g_swarmState.log(std::string("node_add: ") + ctx.args);
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Swarm] Node added: %s (total: %d)\n", ctx.args, static_cast<int>(g_swarmState.nodes.size()));
    ctx.output(buf);
    return CommandResult::ok("swarm.addNode");
}
CommandResult handleSwarmBlacklistNode(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: swarm blacklist <addr>\n"); return CommandResult::error("swarm.blacklistNode: no addr"); }
    std::lock_guard<std::mutex> lk(g_swarmState.mtx);
    for (auto& n : g_swarmState.nodes) { if (n.addr == ctx.args) { n.blacklisted = true; n.active = false; } }
    g_swarmState.log(std::string("node_blacklist: ") + ctx.args);
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Swarm] Node blacklisted: %s\n", ctx.args);
    ctx.output(buf);
    return CommandResult::ok("swarm.blacklistNode");
}
