CommandResult handleSwarmRemoveNode(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: swarm remove_node <addr>\n"); return CommandResult::error("swarm.removeNode: no addr"); }
    std::lock_guard<std::mutex> lk(g_swarmState.mtx);
    std::string target(ctx.args);
    auto it = std::remove_if(g_swarmState.nodes.begin(), g_swarmState.nodes.end(),
        [&](const SwarmState::Node& n) { return n.addr == target; });
    if (it != g_swarmState.nodes.end()) {
        g_swarmState.nodes.erase(it, g_swarmState.nodes.end());
        g_swarmState.log(std::string("node_remove: ") + ctx.args);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[Swarm] Node removed: %s\n", ctx.args); ctx.output(buf);
    } else { ctx.output("[Swarm] Node not found\n"); }
    return CommandResult::ok("swarm.removeNode");
}
