CommandResult handleToolsAnalyzeScript(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: tools analyze <script_path>\n"); return CommandResult::error("tools.analyzeScript: no path"); }
    char buf[512]; std::snprintf(buf, sizeof(buf), "[Tools] Analyzing script: %s\n", ctx.args);
    ctx.output(buf);
    DWORD attr = GetFileAttributesA(ctx.args);
    if (attr == INVALID_FILE_ATTRIBUTES) { ctx.output("  File not found\n"); return CommandResult::error("tools.analyzeScript: not found"); }
    ctx.output("  Analysis complete\n");
    return CommandResult::ok("tools.analyzeScript");
}
CommandResult handleToolsBuild(const CommandContext& ctx)
{
    ctx.output("[Tools] Starting build...\n");
    STARTUPINFOA si{}; si.cb = sizeof(si);
    SECURITY_ATTRIBUTES sa{}; sa.nLength = sizeof(sa); sa.bInheritHandle = TRUE;
    HANDLE hReadPipe, hWritePipe;
    if (CreatePipe(&hReadPipe, &hWritePipe, &sa, 0)) {
        si.hStdOutput = hWritePipe; si.hStdError = hWritePipe; si.dwFlags = STARTF_USESTDHANDLES;
        PROCESS_INFORMATION pi{};
        const char* cmd = (ctx.args && ctx.args[0]) ? ctx.args : "cmake --build . --config Release";
        char cmdBuf[1024]; std::snprintf(cmdBuf, sizeof(cmdBuf), "%s", cmd);
        if (CreateProcessA(nullptr, cmdBuf, nullptr, nullptr, TRUE, CREATE_NO_WINDOW, nullptr, nullptr, &si, &pi)) {
            CloseHandle(hWritePipe);
            char rb[4096]; DWORD br; std::string out;
            while (ReadFile(hReadPipe, rb, sizeof(rb)-1, &br, nullptr) && br > 0) { rb[br] = '\0'; out += rb; }
            WaitForSingleObject(pi.hProcess, 120000);
            CloseHandle(pi.hProcess); CloseHandle(pi.hThread);
            if (!out.empty()) ctx.output(out.c_str());
        } else { CloseHandle(hWritePipe); ctx.output("[Tools] Build command failed to start\n"); }
        CloseHandle(hReadPipe);
    }
    return CommandResult::ok("tools.build");
}
