CommandResult handleToolsProfileStart(const CommandContext& ctx)
{
    std::lock_guard<std::mutex> lk(g_profileState.mtx);
    g_profileState.running = true;
    QueryPerformanceCounter(&g_profileState.startTime);
    ctx.output("[Tools] Profiler started\n");
    return CommandResult::ok("tools.profileStart");
}
CommandResult handleToolsProfileStop(const CommandContext& ctx)
{
    std::lock_guard<std::mutex> lk(g_profileState.mtx);
    if (!g_profileState.running) { ctx.output("[Tools] Profiler not running\n"); return CommandResult::ok("tools.profileStop"); }
    g_profileState.running = false;
    LARGE_INTEGER end, freq;
    QueryPerformanceCounter(&end);
    QueryPerformanceFrequency(&freq);
    double ms = static_cast<double>(end.QuadPart - g_profileState.startTime.QuadPart) * 1000.0 / static_cast<double>(freq.QuadPart);
    char buf[128]; std::snprintf(buf, sizeof(buf), "[Tools] Profiler stopped — duration: %.2f ms\n", ms);
    ctx.output(buf);
    return CommandResult::ok("tools.profileStop");
}
