// ============================================================
// TRANSPARENCY HANDLERS — SetLayeredWindowAttributes Win32 API
// ============================================================
namespace { struct TransparencyState { int pct = 100; bool enabled = false; std::mutex mtx; }; TransparencyState g_transpState; }
static CommandResult setTransparency(const CommandContext& ctx, int pct) {
    {
        std::lock_guard<std::mutex> lk(g_transpState.mtx);
        g_transpState.pct = pct;
        g_transpState.enabled = (pct < 100);
    }
    if (ctx.isGui && ctx.hwnd) {
        HWND h = reinterpret_cast<HWND>(ctx.hwnd);
        LONG style = GetWindowLongA(h, GWL_EXSTYLE);
        if (pct < 100) {
            SetWindowLongA(h, GWL_EXSTYLE, style | WS_EX_LAYERED);
            SetLayeredWindowAttributes(h, 0, static_cast<BYTE>(pct * 255 / 100), LWA_ALPHA);
        } else {
            SetWindowLongA(h, GWL_EXSTYLE, style & ~WS_EX_LAYERED);
        }
    }
    char buf[64]; std::snprintf(buf, sizeof(buf), "[View] Transparency set to %d%%\n", pct);
    ctx.output(buf);
    return CommandResult::ok("transparency.set");
}
CommandResult handleTransparency100(const CommandContext& ctx) { return setTransparency(ctx, 100); }
CommandResult handleTransparency40(const CommandContext& ctx)  { return setTransparency(ctx, 40); }
CommandResult handleTransparency50(const CommandContext& ctx)  { return setTransparency(ctx, 50); }
CommandResult handleTransparency60(const CommandContext& ctx)  { return setTransparency(ctx, 60); }
CommandResult handleTransparency70(const CommandContext& ctx)  { return setTransparency(ctx, 70); }
CommandResult handleTransparency80(const CommandContext& ctx)  { return setTransparency(ctx, 80); }
CommandResult handleTransparency90(const CommandContext& ctx)  { return setTransparency(ctx, 90); }
CommandResult handleTransparencyCustom(const CommandContext& ctx) {
    int pct = 80;
    if (ctx.args && ctx.args[0]) pct = std::atoi(ctx.args);
    if (pct < 10) pct = 10; if (pct > 100) pct = 100;
    return setTransparency(ctx, pct);
}
