CommandResult handleVscextApiLoadNative(const CommandContext& ctx)
{
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: vscext load_native <dll_path>\n"); return CommandResult::error("vscext.api.loadNative: no path"); }
    HMODULE hMod = LoadLibraryA(ctx.args);
    if (hMod) {
        char buf[512]; std::snprintf(buf, sizeof(buf), "[VscExt] Native extension loaded: %s (handle: %p)\n", ctx.args, static_cast<void*>(hMod));
        ctx.output(buf);
    } else {
        char buf[512]; std::snprintf(buf, sizeof(buf), "[VscExt] Failed to load: %s (error: %lu)\n", ctx.args, GetLastError());
        ctx.output(buf);
        return CommandResult::error("vscext.api.loadNative: failed");
    }
    return CommandResult::ok("vscext.api.loadNative");
}
