CommandResult handleBackendSaveConfigs(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_backendState.mtx);
    const char* path = (ctx.args && ctx.args[0]) ? ctx.args : "backend_config.json";
    HANDLE hFile = CreateFileA(path, GENERIC_WRITE, 0, nullptr, CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile != INVALID_HANDLE_VALUE) {
        std::string data = "{\"active\":\"" + g_backendState.active + "\"}\n";
        DWORD written; WriteFile(hFile, data.c_str(), static_cast<DWORD>(data.size()), &written, nullptr);
        CloseHandle(hFile);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[Backend] Config saved to: %s\n", path);
        ctx.output(buf);
    } else ctx.output("[Backend] Failed to save config\n");
    return CommandResult::ok("backend.saveConfigs");
}
