CommandResult handleDbgLaunch(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: dbg launch <executable>\n"); return CommandResult::error("dbg.launch: no exe"); }
    STARTUPINFOA si{}; si.cb = sizeof(si); PROCESS_INFORMATION pi{};
    char cmdBuf[1024]; std::snprintf(cmdBuf, sizeof(cmdBuf), "%s", ctx.args);
    if (CreateProcessA(nullptr, cmdBuf, nullptr, nullptr, FALSE, CREATE_SUSPENDED, nullptr, nullptr, &si, &pi)) {
        std::lock_guard<std::mutex> lk(g_debugState.mtx);
        g_debugState.attached = true; g_debugState.targetPid = pi.dwProcessId; g_debugState.running = false;
        CloseHandle(pi.hThread); CloseHandle(pi.hProcess);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[Debug] Launched (suspended) PID %lu: %s\n", pi.dwProcessId, ctx.args);
        ctx.output(buf);
    } else { ctx.output("[Debug] Failed to launch process\n"); return CommandResult::error("dbg.launch: CreateProcess failed"); }
    return CommandResult::ok("dbg.launch");
}
