// --- Disk handlers ---
CommandResult handleDiskListDrives(const CommandContext& ctx) {
    ctx.output("[Disk] Drives:\n");
    char drives[512]; DWORD len = GetLogicalDriveStringsA(sizeof(drives), drives);
    if (len > 0 && len < sizeof(drives)) {
        char* p = drives;
        while (*p) {
            UINT t = GetDriveTypeA(p);
            const char* ts = "Unknown";
            if (t == DRIVE_FIXED) ts = "Fixed"; else if (t == DRIVE_REMOVABLE) ts = "Removable";
            else if (t == DRIVE_REMOTE) ts = "Network"; else if (t == DRIVE_CDROM) ts = "CD-ROM";
            char buf[128]; std::snprintf(buf, sizeof(buf), "  %s [%s]\n", p, ts);
            ctx.output(buf); p += strlen(p) + 1;
        }
    }
    return CommandResult::ok("disk.listDrives");
}
CommandResult handleDiskScanPartitions(const CommandContext& ctx) {
    ctx.output("[Disk] Partitions:\n");
    char drives[512]; DWORD len = GetLogicalDriveStringsA(sizeof(drives), drives);
    if (len > 0 && len < sizeof(drives)) {
        char* p = drives;
        while (*p) {
            ULARGE_INTEGER freeB, totalB;
            if (GetDiskFreeSpaceExA(p, nullptr, &totalB, &freeB)) {
                char buf[256]; std::snprintf(buf, sizeof(buf), "  %s Total: %.1f GB, Free: %.1f GB\n",
                    p, totalB.QuadPart / (1024.0*1024.0*1024.0), freeB.QuadPart / (1024.0*1024.0*1024.0));
                ctx.output(buf);
            }
            p += strlen(p) + 1;
        }
    }
    return CommandResult::ok("disk.scanPartitions");
}
