CommandResult handleLspSaveConfig(const CommandContext& ctx) {
    const char* path = (ctx.args && ctx.args[0]) ? ctx.args : "lsp_config.json";
    std::lock_guard<std::mutex> lk(g_lspState.mtx);
    HANDLE hFile = CreateFileA(path, GENERIC_WRITE, 0, nullptr, CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile != INVALID_HANDLE_VALUE) {
        std::string data = "{\"server\":\"" + g_lspState.serverCmd + "\",\"running\":" + (g_lspState.running ? "true" : "false") + "}\n";
        DWORD written; WriteFile(hFile, data.c_str(), static_cast<DWORD>(data.size()), &written, nullptr);
        CloseHandle(hFile);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[LSP] Config saved to: %s\n", path); ctx.output(buf);
    } else ctx.output("[LSP] Failed to save config\n");
    return CommandResult::ok("lsp.saveConfig");
}
