// --- Plugin management ---
namespace {
struct PluginInfo { std::string path; HMODULE hMod = nullptr; bool hotload = false; };
struct PluginState { std::vector<PluginInfo> plugins; bool hotloadGlobal = false; std::mutex mtx; };
PluginState g_pluginState;
}
CommandResult handlePluginConfigure(const CommandContext& ctx) {
    ctx.output("[Plugin] Configuration:\n");
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    char buf[128]; std::snprintf(buf, sizeof(buf), "  Hotload: %s | Loaded: %d\n",
        g_pluginState.hotloadGlobal ? "on" : "off", (int)g_pluginState.plugins.size());
    ctx.output(buf); return CommandResult::ok("plugin.configure");
}
CommandResult handlePluginLoad(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: plugin load <path>\n"); return CommandResult::error("plugin.load: no path"); }
    HMODULE hMod = LoadLibraryA(ctx.args);
    if (!hMod) { char buf[256]; std::snprintf(buf, sizeof(buf), "[Plugin] Failed to load: %s (error %lu)\n", ctx.args, GetLastError()); ctx.output(buf); return CommandResult::error("plugin.load: LoadLibrary failed"); }
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    g_pluginState.plugins.push_back({ctx.args, hMod, false});
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Plugin] Loaded: %s\n", ctx.args);
    ctx.output(buf); return CommandResult::ok("plugin.load");
}
CommandResult handlePluginRefresh(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    char buf[64]; std::snprintf(buf, sizeof(buf), "[Plugin] Refreshed %d plugin(s)\n", (int)g_pluginState.plugins.size());
    ctx.output(buf); return CommandResult::ok("plugin.refresh");
}
CommandResult handlePluginScanDir(const CommandContext& ctx) {
    const char* dir = (ctx.args && ctx.args[0]) ? ctx.args : ".";
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Plugin] Scanning: %s\n", dir);
    ctx.output(buf);
    WIN32_FIND_DATAA fd; char pattern[512]; std::snprintf(pattern, sizeof(pattern), "%s\\*.dll", dir);
    HANDLE hFind = FindFirstFileA(pattern, &fd);
    if (hFind != INVALID_HANDLE_VALUE) {
        int cnt = 0;
        do { char fb[256]; std::snprintf(fb, sizeof(fb), "  Found: %s\n", fd.cFileName); ctx.output(fb); cnt++; } while (FindNextFileA(hFind, &fd));
        FindClose(hFind);
        char rb[64]; std::snprintf(rb, sizeof(rb), "[Plugin] Found %d DLL(s)\n", cnt); ctx.output(rb);
    } else ctx.output("[Plugin] No DLLs found\n");
    return CommandResult::ok("plugin.scanDir");
}
CommandResult handlePluginShowPanel(const CommandContext& ctx) {
    ctx.output("[Plugin] Plugin panel\n");
    if (ctx.isGui && ctx.hwnd) PostMessageA(reinterpret_cast<HWND>(ctx.hwnd), WM_COMMAND, 0, 0);
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    for (const auto& p : g_pluginState.plugins) { std::string msg = "  " + p.path + "\n"; ctx.output(msg.c_str()); }
    return CommandResult::ok("plugin.showPanel");
}
CommandResult handlePluginShowStatus(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    char buf[128]; std::snprintf(buf, sizeof(buf), "[Plugin] Status — loaded: %d | hotload: %s\n",
        (int)g_pluginState.plugins.size(), g_pluginState.hotloadGlobal ? "on" : "off");
    ctx.output(buf); return CommandResult::ok("plugin.showStatus");
}
CommandResult handlePluginToggleHotload(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    g_pluginState.hotloadGlobal = !g_pluginState.hotloadGlobal;
    char buf[64]; std::snprintf(buf, sizeof(buf), "[Plugin] Hotload: %s\n", g_pluginState.hotloadGlobal ? "on" : "off");
    ctx.output(buf); return CommandResult::ok("plugin.toggleHotload");
}
CommandResult handlePluginUnload(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: plugin unload <name>\n"); return CommandResult::error("plugin.unload: no name"); }
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    std::string target(ctx.args);
    auto it = std::remove_if(g_pluginState.plugins.begin(), g_pluginState.plugins.end(),
        [&](const PluginInfo& p) { if (p.path.find(target) != std::string::npos) { if (p.hMod) FreeLibrary(p.hMod); return true; } return false; });
    g_pluginState.plugins.erase(it, g_pluginState.plugins.end());
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Plugin] Unloaded: %s\n", ctx.args);
    ctx.output(buf); return CommandResult::ok("plugin.unload");
}
CommandResult handlePluginUnloadAll(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_pluginState.mtx);
    for (auto& p : g_pluginState.plugins) { if (p.hMod) FreeLibrary(p.hMod); }
    int cnt = (int)g_pluginState.plugins.size(); g_pluginState.plugins.clear();
    char buf[64]; std::snprintf(buf, sizeof(buf), "[Plugin] Unloaded %d plugin(s)\n", cnt);
    ctx.output(buf); return CommandResult::ok("plugin.unloadAll");
}
