namespace {
struct ReplayCheckpoint { std::string label; DWORD tick; };
struct ReplayState { std::vector<ReplayCheckpoint> checkpoints; std::mutex mtx; };
ReplayState g_replayState;
}
CommandResult handleReplayCheckpoint(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_replayState.mtx);
    std::string label = (ctx.args && ctx.args[0]) ? ctx.args : "auto";
    g_replayState.checkpoints.push_back({label, GetTickCount()});
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Replay] Checkpoint: %s (#%d)\n", label.c_str(), (int)g_replayState.checkpoints.size());
    ctx.output(buf); return CommandResult::ok("replay.checkpoint");
}
CommandResult handleReplayExportSession(const CommandContext& ctx) {
    const char* path = (ctx.args && ctx.args[0]) ? ctx.args : "session_replay.json";
    std::lock_guard<std::mutex> lk(g_replayState.mtx);
    HANDLE hFile = CreateFileA(path, GENERIC_WRITE, 0, nullptr, CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile != INVALID_HANDLE_VALUE) {
        std::string data = "{\"checkpoints\":" + std::to_string(g_replayState.checkpoints.size()) + "}\n";
        DWORD written; WriteFile(hFile, data.c_str(), static_cast<DWORD>(data.size()), &written, nullptr);
        CloseHandle(hFile);
        char buf[256]; std::snprintf(buf, sizeof(buf), "[Replay] Session exported to: %s\n", path); ctx.output(buf);
    } else ctx.output("[Replay] Failed to export session\n");
    return CommandResult::ok("replay.exportSession");
}
CommandResult handleReplayShowLast(const CommandContext& ctx) {
    std::lock_guard<std::mutex> lk(g_replayState.mtx);
    if (g_replayState.checkpoints.empty()) { ctx.output("[Replay] No checkpoints\n"); return CommandResult::ok("replay.showLast"); }
    const auto& cp = g_replayState.checkpoints.back();
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Replay] Last checkpoint: %s (tick %lu)\n", cp.label.c_str(), cp.tick);
    ctx.output(buf); return CommandResult::ok("replay.showLast");
}
