// --- Vision ---
CommandResult handleVisionAnalyzeImage(const CommandContext& ctx) {
    if (!ctx.args || !ctx.args[0]) { ctx.output("Usage: vision analyze <image_path>\n"); return CommandResult::error("vision.analyze: no path"); }
    DWORD attr = GetFileAttributesA(ctx.args);
    if (attr == INVALID_FILE_ATTRIBUTES) { ctx.output("[Vision] Image not found\n"); return CommandResult::error("vision.analyze: not found"); }
    char buf[256]; std::snprintf(buf, sizeof(buf), "[Vision] Analyzing: %s\n", ctx.args);
    ctx.output(buf); return tryHeadlessAgentRoute("handleVisionAnalyzeImage", ctx);
}
